package main

import "strings"

// AdminEntityGroup defines the substitution map and file pairings for one
// admin/non-admin entity group. The admin file is the SOURCE OF TRUTH.
// Non-admin files are generated by stripping "Admin" from entity-specific tokens.
//
// This direction is unambiguous: tokens with "Admin" get it removed, tokens
// without "Admin" (shared types like PublishRequest) pass through unchanged.
type AdminEntityGroup struct {
	Name  string     // "content", "datatype", etc.
	Pairs []FilePair // source (admin) → target (non-admin) file pairs
	// replacer is built from Subs at init time.
	replacer *strings.Replacer
	// Subs lists all (old, new) pairs: admin token → non-admin token.
	Subs []Sub
}

// FilePair maps an admin source file to its non-admin target.
type FilePair struct {
	Source string // admin file (source of truth)
	Target string // non-admin file (generated)
}

// Sub is a single string substitution pair.
type Sub struct {
	Old string // admin token
	New string // non-admin token
}

// Replacer returns a strings.Replacer built from the substitution pairs.
func (g *AdminEntityGroup) Replacer() *strings.Replacer {
	if g.replacer != nil {
		return g.replacer
	}
	args := make([]string, 0, len(g.Subs)*2)
	for _, s := range g.Subs {
		args = append(args, s.Old, s.New)
	}
	g.replacer = strings.NewReplacer(args...)
	return g.replacer
}

// AdminEntityGroups defines all admin/non-admin entity groups.
var AdminEntityGroups = []AdminEntityGroup{
	contentGroup(),
	datatypeGroup(),
	fieldGroup(),
	routeGroup(),
	fieldTypeGroup(),
}

// ---------------------------------------------------------------------------
// Content group — content data, content fields, versions, relations, publish
// ---------------------------------------------------------------------------

func contentGroup() AdminEntityGroup {
	return AdminEntityGroup{
		Name: "content",
		Pairs: []FilePair{
			// Service layer (admin → non-admin)
			{Source: "internal/service/content_admin.go", Target: "internal/service/content.go"},
			{Source: "internal/service/content_versions_admin.go", Target: "internal/service/content_versions.go"},
			{Source: "internal/service/content_relations_admin.go", Target: "internal/service/content_relations.go"},
			{Source: "internal/service/content_publish_admin.go", Target: "internal/service/content_publish.go"},
			{Source: "internal/service/content_fields_admin.go", Target: "internal/service/content_fields.go"},
			// Router layer (admin → non-admin)
			{Source: "internal/router/adminContentData.go", Target: "internal/router/contentData.go"},
			{Source: "internal/router/adminContentFields.go", Target: "internal/router/contentFields.go"},
			{Source: "internal/router/adminTree.go", Target: "internal/router/contentTree.go"},
			{Source: "internal/router/versions_admin.go", Target: "internal/router/versions.go"},
			{Source: "internal/router/publish_admin.go", Target: "internal/router/publish.go"},
		},
		Subs: contentSubs(),
	}
}

func contentSubs() []Sub {
	return []Sub{
		// === Nullable types (strip Admin) ===
		{"NullableAdminContentVersionID", "NullableContentVersionID"},
		{"NullableAdminContentRelationID", "NullableContentRelationID"},
		{"NullableAdminContentFieldID", "NullableContentFieldID"},
		{"NullableAdminContentID", "NullableContentID"},
		{"NullableAdminDatatypeID", "NullableDatatypeID"},
		{"NullableAdminRouteID", "NullableRouteID"},
		{"NullableAdminFieldID", "NullableFieldID"},

		// === Compound entity/view/param types ===
		{"AdminContentDataTopLevel", "ContentDataTopLevel"},
		{"AdminContentDataView", "ContentDataView"},
		{"AdminContentDataJSON", "ContentDataJSON"},

		// === ID types ===
		{"AdminContentVersionID", "ContentVersionID"},
		{"AdminContentRelationID", "ContentRelationID"},
		{"AdminContentFieldID", "ContentFieldID"},
		{"AdminContentDataID", "ContentDataID"},

		// === Entity types ===
		{"AdminContentVersion", "ContentVersion"},
		{"AdminContentRelation", "ContentRelation"},
		{"AdminContentFields", "ContentFields"},
		{"AdminContentField", "ContentField"},
		{"AdminContentData", "ContentData"},

		// === Bare AdminContentID (after all compounds) ===
		{"AdminContentID", "ContentID"},

		// === Service/constructor/registry ===
		{"AdminContentService", "ContentService"},
		{"NewAdminContentService", "NewContentService"},
		{"svc.AdminContent.", "svc.Content."},
		{"svc.AdminContent)", "svc.Content)"},

		// === Foreign key struct fields (strip Admin prefix) ===
		{".AdminRouteID", ".RouteID"},
		{".AdminDatatypeID", ".DatatypeID"},
		{".AdminFieldID", ".FieldID"},
		{"AdminRouteID:", "RouteID:"},
		{"AdminDatatypeID:", "DatatypeID:"},
		{"AdminFieldID:", "FieldID:"},

		// === FK ID types ===
		{"types.AdminRouteID", "types.RouteID"},
		{"types.AdminDatatypeID", "types.DatatypeID"},
		{"types.AdminFieldID", "types.FieldID"},

		// === Publishing functions ===
		{"PublishAdminContent", "PublishContent"},
		{"UnpublishAdminContent", "UnpublishContent"},
		{"BuildAdminSnapshot", "BuildSnapshot"},
		{"RestoreAdminContent", "RestoreContent"},
		{"PruneExcessAdminVersions", "PruneExcessVersions"},

		// === DB driver methods ===
		{"GetAdminContentTreeByRoute", "GetContentTreeByRoute"},
		{"ListAdminFieldsByDatatypeID", "ListFieldsByDatatypeID"},
		{"AssembleAdminContentDataView", "AssembleContentDataView"},
		{"adminContentIDToNullable", "contentIDToNullable"},
		{"autoCreateAdminFields", "autoCreateFields"},

		// === Router handler names ===
		{"AdminContentDatasHandler", "ContentDatasHandler"},
		{"AdminContentDataHandler", "ContentDataHandler"},
		{"AdminContentDataFullHandler", "ContentDataFullHandler"},
		{"AdminContentFieldsHandler", "ContentFieldsHandler"},
		{"AdminContentFieldHandler", "ContentFieldHandler"},
		{"AdminContentTreeSaveHandler", "ContentTreeSaveHandler"},

		// === Admin-prefixed field value ===
		{".AdminFieldValue", ".FieldValue"},
		{"AdminFieldValue:", "FieldValue:"},

		// === Error/log strings ===
		{`"admin_content_data"`, `"content_data"`},
		{`"admin_content_field"`, `"content_field"`},
		{`"admin_content_version"`, `"content_version"`},
		{`"admin_content_relation"`, `"content_relation"`},
		{`"admin content data"`, `"content data"`},
		{`"admin content field"`, `"content field"`},
		{`"admin content version"`, `"content version"`},
		{`"admin content relation"`, `"content relation"`},
		{`"admin content node"`, `"content node"`},

		// === Comment labels ===
		{"// Admin content ", "// Content "},
		{"// admin content ", "// content "},
		{"--- Admin Content ", "--- Content "},
		{"--- admin content ", "--- content "},
		{"admin create:", "create:"},
		{"admin publish", "publish"},
		{"admin reorder", "reorder"},
		{"admin restore", "restore"},
	}
}

